function highlightDifferences(){const s=$("#carHistoryTable tbody tr");s.each(function(n){if(n===s.length-1)return;const i=$(this),a=s.eq(n+1),c=i.find("td"),l=a.find("td");c.each(function(r){if(r<=1)return;const t=$(this).text().trim(),e=l.eq(r).text().trim();t!==e&&($(this).removeClass("table-success table-danger table-info"),t!==""&&e===""?$(this).addClass("table-success"):t===""&&e!==""?$(this).addClass("table-danger"):t!==""&&e!==""&&$(this).addClass("table-info"))})})}
